        return render_template('write_review.html', dishes=dishes, error_message=error_message)

    # Validate rating
    try:
        rating = int(rating_str)
        if rating < 1 or rating > 5:
            raise ValueError
    except ValueError:
        error_message = "Rating must be between 1 and 5."
        return render_template('write_review.html', dishes=dishes, error_message=error_message)

    if not review_text:
