def root_redirect():
    return redirect(url_for('dashboard'))


@app.route('/dashboard')
def dashboard():
    user = get_current_user()
    username = user['username'] if user else 'Guest'

    menu = load_menu()
    # Featured dishes: top 3 by avg_rating
    featured_dishes_raw = sorted(menu, key=lambda d: d['avg_rating'], reverse=True)[:3]
    featured_dishes = []
    for dish in featured_dishes_raw:
        featured_dishes.append({
